const body = $input.first().json.body || $input.first().json;

const update_id = body.update_id;
let type = 'unknown';
let from = {};
let text = '';
let chat_id = '';
let data = '';

if (body.message) {
  type = 'message';
  from = body.message.from || {};
  text = body.message.text || body.message.caption || '[media/sticker]';
  chat_id = body.message.chat?.id;
} else if (body.callback_query) {
  type = 'callback_query';
  from = body.callback_query.from || {};
  data = body.callback_query.data || '';
  chat_id = body.callback_query.message?.chat?.id;
  text = `[CALLBACK] ${data}`;
}

const user_display = from.username ? `@${from.username}` : `${from.first_name || ''} ${from.last_name || ''}`.trim();
const ts = new Date().toISOString();

return [{
  json: {
    ts,
    update_id,
    type,
    chat_id,
    user_id: from.id,
    user: user_display,
    text,
    raw: body
  }
}];
